{
  "integrative": {
    "title": "Integrative Close: From Material to Motor",
    "objective": "Synthesize the relationship between material resistivity, total circuit resistance, and the resulting voltage drop at the point of use.",
    "retrievalTextLines": [
      "Resistivity (ρ) is the fixed property of the material (Ohm-metres).",
      "Resistance (R) is the total opposition of the specific cable (Ohms).",
      "Voltage drop is the loss of electrical pressure along the conductor."
    ],
    "questionText": "A 100-metre cable made of a high-resistivity material is replaced with a cable of the identical length and thickness but made of a lower-resistivity material. Explain how this change in material property (resistivity) affects the total resistance of the run and the resulting voltage available at the end of the circuit.",
    "answerGuidance": [
      "Lower resistivity (ρ) means the material is naturally a better conductor at a molecular level.",
      "Because the dimensions (length and thickness) remain the same, the lower resistivity directly results in a lower total resistance (R) for the cable run.",
      "Lower resistance means less electrical pressure (potential difference) is 'used up' or lost as current flows through the cable.",
      "This reduction in voltage drop ensures that a higher percentage of the source voltage is available to power the equipment at the end of the circuit."
    ],
    "hint": "Think about the chain reaction: how does changing the 'DNA' of the metal (resistivity) change the 'friction' (resistance), and how does that change the 'pressure' (voltage) reaching the load?"
  }
}

